using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var openAiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Tools ---
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Chat client with automatic function invocation ---
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(openAiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- System prompt that drives the agent loop ---
var systemPrompt = """
    You are a research agent. Your job is to research a topic thoroughly
    using the tools available to you.

    Workflow:
    1. Break the topic into 3-5 key questions.
    2. Use the SearchWeb tool to find information for each question.
    3. Use the AddNote tool to record every important finding.
    4. After gathering enough information, use GetNotes to review your notes.
    5. Provide a comprehensive, well-structured summary of your research.

    Always search multiple aspects of the topic and take detailed notes
    before writing the final summary.
    """;

// --- Get topic from user ---
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

// --- Run the agent ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt),
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var response = await client.GetResponseAsync(
    messages, new() { Tools = tools });

Console.WriteLine("\n========== Research Summary ==========\n");
Console.WriteLine(response.Text);

if (notebook.Notes.Count > 0)
{
    Console.WriteLine("\n========== Research Notes ==========\n");
    foreach (var (i, note) in notebook.Notes.Select((n, i) => (i, n)))
        Console.WriteLine($"  [{i + 1}] {note}");
}

// ---------------------------------------------------------------------------
// Tool: Web search via DuckDuckGo Instant Answer API (no key required)
// ---------------------------------------------------------------------------
[Description("Searches the web for a query and returns relevant results.")]
static async Task<string> SearchWeb(
    [Description("The search query string")] string query)
{
    Console.WriteLine($"  🔍 Searching: {query}");
    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (compatible; research bot)");

        var encoded = WebUtility.UrlEncode(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await http.GetStringAsync(url);

        using var doc = JsonDocument.Parse(json);
        var root = doc.RootElement;
        var results = new List<string>();

        var abstractText = root.GetProperty("AbstractText").GetString();
        if (!string.IsNullOrEmpty(abstractText))
        {
            var source = root.GetProperty("AbstractSource").GetString();
            results.Add($"From {source}: {abstractText}");
        }

        if (root.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var item in topics.EnumerateArray().Take(5))
            {
                if (item.TryGetProperty("Text", out var text))
                    results.Add($"- {text.GetString()}");
            }
        }

        return results.Count > 0
            ? string.Join("\n", results)
            : $"No detailed results found for '{query}'. Try rephrasing.";
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}. Try a different query.";
    }
}

// ---------------------------------------------------------------------------
// Tool: Notebook for collecting research findings
// ---------------------------------------------------------------------------
class Notebook
{
    public List<string> Notes { get; } = [];

    [Description("Saves a research note for later reference.")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        Notes.Add(note);
        Console.WriteLine($"  📝 Note saved ({Notes.Count} total)");
        return $"Note saved. You now have {Notes.Count} note(s).";
    }

    [Description("Retrieves all saved research notes.")]
    public string GetNotes()
    {
        if (Notes.Count == 0) return "No notes saved yet.";
        return string.Join("\n",
            Notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

